window.roundUpVolume = function(val) {
  if (val === null || val === undefined || isNaN(val) || val === '') return null;
  return Math.ceil(Math.round(val * 10000000) / 100) / 100000;
};

window.wmsColumnFilters = window.wmsColumnFilters || {};

window.getPeriodColor = function(period) {
  if (!period) return { bg: '#e5e7eb', text: '#374151' };
  let hash = 0;
  for (let i = 0; i < period.length; i++) {
    hash = period.charCodeAt(i) + ((hash << 5) - hash);
  }
  const hue = Math.abs(hash % 360);
  const bg = `hsl(${hue}, 65%, 85%)`;
  const text = `hsl(${hue}, 70%, 25%)`;
  return { bg, text };
};

window.pickerOperatorsMap = window.pickerOperatorsMap || {};

window.fetchPickerOperators = async function(ordersList) {
  if (!ordersList || ordersList.length === 0) return;
  const client = window.supabase ? window.supabase.createClient(
    'https://hpomymtecmxujbjxqawu.supabase.co',
    'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imhwb215bXRlY214dWpianhxYXd1Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3Nzk5OTE1NzAsImV4cCI6MjA5NTU2NzU3MH0.HD7Fbt7k95N9lB6NBGM87k3eFeZFDGLJK_Tp3EHT6JQ'
  ) : null;
  if (!client) return;

  try {
    const orderNumbers = ordersList.map(o => String(o.external_order_number || o.id));
    const chunkSize = 200;
    for (let i = 0; i < orderNumbers.length; i += chunkSize) {
      const chunk = orderNumbers.slice(i, i + chunkSize);
      
      const { data: activeOps, error: activeOpsErr } = await client
        .from('active_orders')
        .select('order_number, operator')
        .in('order_number', chunk);
      
      if (!activeOpsErr && activeOps) {
        activeOps.forEach(item => {
          if (item.operator) {
            window.pickerOperatorsMap[item.order_number] = item.operator;
          }
        });
      }
      
      const { data: histOps, error: histOpsErr } = await client
        .from('history_logs')
        .select('pedido, picker')
        .in('pedido', chunk);
        
      if (!histOpsErr && histOps) {
        histOps.forEach(item => {
          if (item.picker && item.picker !== '-') {
            window.pickerOperatorsMap[item.pedido] = item.picker;
          }
        });
      }
    }
  } catch (err) {
    console.warn('[Picker Operators Sync] Error fetching operators:', err);
  }
};

window.fetchInventoryForOrders = async function(orders) {
  window.loadedOrdersInventoryMap = window.loadedOrdersInventoryMap || {};
  if (!orders || orders.length === 0) return;

  const allProductIds = [];
  orders.forEach(o => {
    (o.order_items || []).forEach(oi => {
      if (oi.product_id && !oi.products?.is_virtual) {
        allProductIds.push(oi.product_id);
      }
    });
  });

  const uniqueProductIds = [...new Set(allProductIds)].filter(id => {
    return !Object.keys(window.loadedOrdersInventoryMap).some(key => key.startsWith(id + '_'));
  });

  if (uniqueProductIds.length === 0) return;

  try {
    const { data: invData } = await supabase
      .from('inventory')
      .select('product_id, warehouse_id, quantity')
      .in('product_id', uniqueProductIds);

    if (invData) {
      invData.forEach(inv => {
        window.loadedOrdersInventoryMap[`${inv.product_id}_${inv.warehouse_id}`] = inv.quantity || 0;
      });
    }
  } catch (e) {
    console.error('Error fetching inventory for order stock check:', e);
  }
};

