console.log('DEBUG: Iniciando js/admin.js...');

function getDisplayStatusName(rawStatus) {
  if (!rawStatus) return 'Desconocido';
  const statusLower = rawStatus.trim().toLowerCase();
  switch (statusLower) {
    case 'delivered':
      return 'Entregado';
    case 'reviewing':
      return 'Creado';
    case 'skipped':
      return 'Reprogramado';
    default:
      const clean = rawStatus.replace(/_/g, ' ').trim();
      return clean.charAt(0).toUpperCase() + clean.slice(1).toLowerCase();
  }
}

async function init() {
  console.log('DEBUG: Ejecutando función init()...');
  const userEmailSpan = document.getElementById('user-email');
  const logoutBtn = document.getElementById('logout-btn');
  const viewTitle = document.getElementById('view-title');
  const navItems = document.querySelectorAll('.nav-item');

  try {
    // Verify authentication & Admin Role
    console.log('DEBUG: Obteniendo sesión de Supabase...');
    const { data: { session }, error } = await supabase.auth.getSession();

    if (error) {
      console.error('DEBUG: Error al obtener sesión:', error);
    }

    if (!session) {
      console.warn('DEBUG: No hay sesión activa. Redirigiendo a index.html...');
      window.location.href = 'index.html';
      return;
    }

    console.log('DEBUG: Sesión activa encontrada para el usuario:', session.user.email);

    console.log('DEBUG: Consultando perfil de administrador para ID:', session.user.id);
    const { data: profile, error: profileError } = await supabase
      .from('profiles')
      .select('role, company_name, full_name, allowed_modules, comercio')
      .eq('id', session.user.id)
      .single();
    
    if (profileError) {
      console.warn('DEBUG: Error al obtener perfil:', profileError);
    } else {
      console.log('DEBUG: Perfil encontrado:', profile);
    }
    
    if (!profile || profile.role !== 'admin') {
      console.warn('DEBUG: Acceso denegado, no es administrador. Redirigiendo...');
      alert("Acceso denegado. Se requieren permisos de Administrador.");
      window.location.href = 'dashboard.html';
      return;
    }

    userRole = profile.role || 'admin';

    // Auto-update admin profile if missing integrations or documentation_admin
    if (profile.allowed_modules && profile.allowed_modules !== 'all') {
      let currentModules = profile.allowed_modules.split(',').map(m => m.trim());
      let updated = false;
      if (!currentModules.includes('integrations')) {
        currentModules.push('integrations');
        updated = true;
      }
      if (!currentModules.includes('documentation_admin')) {
        currentModules.push('documentation_admin');
        updated = true;
      }
      if (!currentModules.includes('inventory_admin')) {
        currentModules.push('inventory_admin');
        updated = true;
      }
      if (updated) {
        const updatedStr = currentModules.filter(Boolean).join(',');
        console.log('DEBUG: Auto-agregando módulos a la cuenta administrador:', updatedStr);
        await supabase
          .from('profiles')
          .update({ allowed_modules: updatedStr })
          .eq('id', session.user.id);
        profile.allowed_modules = updatedStr;
      }
    }

    // Set user info
    const user = session.user;
    if (userEmailSpan) {
      const displayName = profile?.full_name || user.user_metadata?.full_name || profile?.company_name || user.email;
      userEmailSpan.textContent = `${displayName} (ADMIN)`;
    }

    // Check billing suspension status for assigned commerce
    if (profile && profile.comercio) {
      checkBillingSuspension(profile.comercio);
    }
    
    // Restaurar y configurar el estado colapsado del sidebar
    const sidebar = document.querySelector('.sidebar');
    const toggleSidebarBtn = document.getElementById('toggle-sidebar');
    const toggleIcon = toggleSidebarBtn?.querySelector('i');
    
    const isSidebarCollapsed = localStorage.getItem('sidebar-collapsed') === 'true';
    if (isSidebarCollapsed && sidebar) {
      sidebar.classList.add('collapsed');
      if (toggleSidebarBtn) toggleSidebarBtn.setAttribute('title', 'Expandir menú');
      if (toggleIcon) toggleIcon.className = 'ri-menu-unfold-line';
    }

    if (toggleSidebarBtn) {
      toggleSidebarBtn.addEventListener('click', () => {
        if (sidebar) {
          sidebar.classList.toggle('collapsed');
          const collapsed = sidebar.classList.contains('collapsed');
          localStorage.setItem('sidebar-collapsed', collapsed ? 'true' : 'false');
          if (toggleSidebarBtn) {
            toggleSidebarBtn.setAttribute('title', collapsed ? 'Expandir menú' : 'Contraer menú');
          }
          if (toggleIcon) {
            toggleIcon.className = collapsed ? 'ri-menu-unfold-line' : 'ri-menu-fold-line';
          }
        }
      });
    }

    // Navigation and Filtering
    if (navItems) {
      navItems.forEach(item => {
        item.addEventListener('click', (e) => {
          e.preventDefault();
          const targetItem = e.target.closest('.nav-item');
          if (!targetItem) return;

          navItems.forEach(n => n.classList.remove('active'));
          targetItem.classList.add('active');

          const view = targetItem.getAttribute('data-view');
          console.log('DEBUG: Navegando a vista administrador:', view);
          
          if (view === 'dashboard') {
            viewTitle.textContent = 'Dashboard Admin';
            renderAdminDashboard();
          } else if (view === 'notifications_admin') {
            viewTitle.textContent = 'Notificaciones y Avisos';
            renderNotificationsAdmin();
          } else if (view === 'orders_admin') {
            viewTitle.textContent = 'Gestor de Pedidos';
            renderAdminOrders();
          } else if (view === 'inventory_admin') {
            viewTitle.textContent = 'Inventario';
            renderAdminInventory();
          } else if (view === 'consolidated_shipments') {
            viewTitle.textContent = 'Envíos Consolidados';
            renderConsolidatedShipments();
          } else if (view === 'reassign_admin') {
            viewTitle.textContent = 'Reubicar Stock';
            renderReassignStock();
          } else if (view === 'manual_in_admin') {
            viewTitle.textContent = 'Ingreso Manual';
            renderManualIn();
          } else if (view === 'declarations_admin') {
            viewTitle.textContent = 'Ingresos de Stock';
            renderDeclarationsAdmin();
          } else if (view === 'upload_products_admin') {
            viewTitle.textContent = 'Carga de Planillas';
            renderUploadProducts();
          } else if (view === 'catalog') {
            viewTitle.textContent = 'Catálogo & Equivalencias';
            renderAdminCatalog();
          } else if (view === 'onboarding_admin') {
            viewTitle.textContent = 'Solicitudes de Alta';
            renderOnboardingAdmin();
          } else if (view === 'users_admin') {
            viewTitle.textContent = 'Gestionar Usuarios';
            renderUsersAdmin();
          } else if (view === 'merchants_admin') {
            viewTitle.textContent = 'Gestionar Comercios';
            renderMerchantsAdmin();
          } else if (view === 'warehouses_admin') {
            viewTitle.textContent = 'Gestionar Bodegas';
            renderWarehousesAdmin();
          } else if (view === 'visibility_rules_admin') {
            viewTitle.textContent = 'Reglas de Visibilidad';
            renderVisibilityRulesAdmin();
          } else if (view === 'integrations') {
            viewTitle.textContent = 'Integraciones';
            renderIntegrations();
          } else if (view === 'billing_admin') {
            viewTitle.textContent = 'Facturación';
            renderBillingAdmin();
          } else if (view === 'volumen_diario_admin') {
            viewTitle.textContent = 'Registro de Volumen Diario';
            renderVolumenDiarioAdmin();
          } else if (view === 'profile') {
            viewTitle.textContent = 'Mi Perfil';
            renderProfile();
          } else if (view === 'inbox') {
            viewTitle.textContent = 'Mi Inbox';
            renderInboxPage();
          } else if (view === 'tickets_admin') {
            viewTitle.textContent = 'Gestión de Tickets';
            const appContent = document.getElementById('app-content');
            renderTicketsAdmin(appContent);
          } else if (view === 'incidencias_admin') {
            viewTitle.textContent = 'Gestión de Incidencias';
            const appContent = document.getElementById('app-content');
            renderIncidenciasAdmin(appContent);
          } else if (view === 'documentation_admin') {
            viewTitle.textContent = 'Documentación del Servicio';
            renderDocsAdmin();
          }
        });
      });
    }

    // Filter Navigation based on allowed_modules for Admin
    const allowedModulesStr = profile?.allowed_modules || 'all';
    let allowedModules = [];
    let firstVisibleItem = null;

    if (navItems) {
      if (allowedModulesStr !== 'all' && allowedModulesStr !== null && allowedModulesStr !== '') {
        allowedModules = allowedModulesStr.split(',').map(m => m.trim());
        
        navItems.forEach(item => {
          const view = item.getAttribute('data-view');
          if (allowedModules.includes(view) || view === 'dashboard' || view === 'profile' || view === 'inbox' || view === 'notifications_admin') {
            const parentLi = item.closest('li');
            if (parentLi) parentLi.style.display = 'block';
            else item.style.display = 'block';
            if (!firstVisibleItem) firstVisibleItem = item;
          } else {
            const parentLi = item.closest('li');
            if (parentLi) parentLi.style.display = 'none';
            else item.style.display = 'none';
          }
        });
      } else {
        // Por defecto, si es 'all' todos los ítems de navegación están permitidos
        if (navItems.length > 0) firstVisibleItem = navItems[0];
      }
      // Ocultar cabeceras de categorías vacías
      updateCategoryHeadersVisibility();
    }

    // Initial View selection based on allowed modules
    if (firstVisibleItem) {
      const defaultView = 'dashboard';
      const isDefaultAllowed = true;
      
      if (isDefaultAllowed) {
        viewTitle.textContent = 'Dashboard Admin';
        console.log('DEBUG: Renderizando vista Dashboard Admin...');
        renderAdminDashboard();
      } else {
        console.log('DEBUG: Vista por defecto restringida, seleccionando primer módulo permitido:', firstVisibleItem.getAttribute('data-view'));
        firstVisibleItem.click();
      }
    } else {
      const appContent = document.getElementById('app-content');
      appContent.innerHTML = `<div class="card" style="padding: 2rem; text-align: center;"><p style="color: var(--color-text-muted);">No tienes módulos asignados. Contacta al propietario del sistema.</p></div>`;
      viewTitle.textContent = 'Sin Acceso';
    }

    // Logout
    if (logoutBtn) {
      logoutBtn.addEventListener('click', async () => {
        console.log('DEBUG: Cerrando sesión...');
        await supabase.auth.signOut();
        window.location.href = 'index.html';
      });
    }

    // Event delegation for dynamic actions
    document.addEventListener('change', async (e) => {
      if (e.target && e.target.classList.contains('status-select')) {
        const orderId = e.target.getAttribute('data-order-id');
        const newStatus = e.target.value;
        console.log(`DEBUG: Cambiando estado de pedido ${orderId} a ${newStatus}...`);
        await updateOrderStatus(orderId, newStatus);
      } else if (e.target && e.target.classList.contains('wms-status-select')) {
        const orderId = e.target.getAttribute('data-order-id');
        const newWmsStatus = e.target.value;
        console.log(`DEBUG: Cambiando estado WMS de pedido ${orderId} a ${newWmsStatus}...`);
        await window.updateWmsOrderStatus(orderId, newWmsStatus);
      }
    });

    // Notification Logic
    initNotifications(session.user.id);

  } catch (err) {
    console.error('DEBUG: Error crítico durante la inicialización de admin.js:', err);
  }
}

// Ocultar cabeceras de categorías vacías en el menú
function updateCategoryHeadersVisibility() {
  const listItems = Array.from(document.querySelectorAll('.sidebar-nav > ul > li'));
  let currentHeader = null;
  let hasVisibleItems = false;
  
  listItems.forEach(li => {
    if (li.classList.contains('sidebar-category-header')) {
      if (currentHeader && !hasVisibleItems) {
        currentHeader.style.display = 'none';
      }
      currentHeader = li;
      hasVisibleItems = false;
    } else {
      if (li.style.display !== 'none') {
        hasVisibleItems = true;
      }
    }
  });
  
  if (currentHeader && !hasVisibleItems) {
    currentHeader.style.display = 'none';
  }

  // Initial badge update and periodic refresh
  window.updateAdminBadges();
  setInterval(window.updateAdminBadges, 60000);
}

window.updateAdminBadges = async function() {
  try {
    // 1. Tickets
    const { count: ticketsCount } = await supabase
      .from('tickets')
      .select('*', { count: 'exact', head: true })
      .in('status', ['abierto', 'en_proceso']);
    
    const badgeTickets = document.getElementById('badge-tickets');
    if (badgeTickets && ticketsCount !== null) {
      badgeTickets.textContent = ticketsCount;
      badgeTickets.style.display = ticketsCount > 0 ? 'inline-flex' : 'none';
    }

    // 2. Billing
    const { count: billingCount } = await supabase
      .from('payment_reports')
      .select('*', { count: 'exact', head: true })
      .eq('status', 'pendiente');
      
    const badgeBilling = document.getElementById('badge-billing');
    if (badgeBilling && billingCount !== null) {
      badgeBilling.textContent = billingCount;
      badgeBilling.style.display = billingCount > 0 ? 'inline-flex' : 'none';
    }
    const internalBillingBadge = document.getElementById('pending-reports-badge');
    if (internalBillingBadge && billingCount !== null) {
      internalBillingBadge.textContent = billingCount;
      internalBillingBadge.style.display = billingCount > 0 ? 'inline-block' : 'none';
    }

    // 3. Users
    const { count: usersCount } = await supabase
      .from('profiles')
      .select('*', { count: 'exact', head: true })
      .eq('role', 'observer');
      
    const badgeUsers = document.getElementById('badge-users');
    if (badgeUsers && usersCount !== null) {
      badgeUsers.textContent = usersCount;
      badgeUsers.style.display = usersCount > 0 ? 'inline-flex' : 'none';
    }

    // 4. Declarations
    const { count: decCount } = await supabase
      .from('stock_declarations')
      .select('*', { count: 'exact', head: true })
      .neq('status', 'Recibido Conforme')
      .neq('status', 'Recibido con Incidencias');
      
    const badgeDecs = document.getElementById('badge-declarations');
    if (badgeDecs && decCount !== null) {
      badgeDecs.textContent = decCount;
      badgeDecs.style.display = decCount > 0 ? 'inline-flex' : 'none';
    }

    // 5. Integrations
    const fortyEightHoursAgo = new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString();
    const { count: integrationsCount } = await supabase
      .from('merchant_integrations')
      .select('*', { count: 'exact', head: true })
      .gte('created_at', fortyEightHoursAgo);
      
    const badgeIntegrations = document.getElementById('badge-integrations');
    if (badgeIntegrations && integrationsCount !== null) {
      badgeIntegrations.textContent = integrationsCount;
      badgeIntegrations.style.display = integrationsCount > 0 ? 'inline-flex' : 'none';
    }

    // 7. Incidencias Admin
    try {
      const { count: incidenciasCount, error: incErr } = await supabase
        .from('incidencias')
        .select('*', { count: 'exact', head: true })
        .eq('status', 'pendiente');
        
      const badgeIncidenciasAdmin = document.getElementById('badge-incidencias-admin');
      if (badgeIncidenciasAdmin && incidenciasCount !== null && !incErr) {
        badgeIncidenciasAdmin.textContent = incidenciasCount;
        badgeIncidenciasAdmin.style.display = incidenciasCount > 0 ? 'inline-flex' : 'none';
      } else if (incErr && (incErr.code === '42P01' || incErr.message.includes('does not exist'))) {
        if (badgeIncidenciasAdmin) badgeIncidenciasAdmin.style.display = 'none';
      }
    } catch (err) {
      console.warn('Error fetching incidencias count for admin badge:', err);
    }

    // 7. Onboarding Admin
    try {
      const { count: onboardingCount, error: onbErr } = await supabase
        .from('onboarding_requests')
        .select('*', { count: 'exact', head: true })
        .eq('status', 'pending');

      const badgeOnboarding = document.getElementById('badge-onboarding');
      if (badgeOnboarding && onboardingCount !== null && !onbErr) {
        badgeOnboarding.textContent = onboardingCount;
        badgeOnboarding.style.display = onboardingCount > 0 ? 'inline-flex' : 'none';
      }
    } catch (err) {
      console.warn('Error fetching onboarding count for admin badge:', err);
    }

  } catch (e) {
    console.error('Error updating admin badges:', e);
  }
};

