window.markDashboardInvoiceAsIssued = async function(recordId, serviceType) {
  showSavingBadge(true);
  try {
    // 1. Obtener detalles del registro de facturación
    const { data: record, error: getRecErr } = await supabase
      .from('billing_records')
      .select('*, billing_periods(name)')
      .eq('id', recordId)
      .single();
      
    if (getRecErr) throw getRecErr;
    if (!record) throw new Error('No se encontró el registro de facturación.');

    showSavingBadge(false);

    // 2. Crear y renderizar el modal
    let modal = document.getElementById('modal-register-dashboard-invoice');
    if (modal) modal.remove();

    modal = document.createElement('div');
    modal.id = 'modal-register-dashboard-invoice';
    modal.className = 'modal-overlay active';
    modal.innerHTML = `
      <div class="modal-content" style="max-width: 450px; width: 90%;">
        <div class="modal-header">
          <h3><i class="ri-file-add-line" style="color: var(--color-primary); margin-right: 0.5rem;"></i> Registrar Factura Oficial</h3>
          <button class="modal-close" onclick="this.closest('.modal-overlay').remove()">&times;</button>
        </div>
        <form id="form-register-dashboard-invoice">
          <div class="modal-body" style="padding: 1.25rem;">
            <div style="font-size: 0.8rem; background: rgba(37, 99, 235, 0.05); color: var(--color-primary); padding: 0.75rem; border-radius: var(--radius-sm); border: 1px solid rgba(37, 99, 235, 0.15); margin-bottom: 1.25rem; line-height: 1.45;">
              Registrando factura de <strong>${serviceType === 'fulfillment' ? 'Fulfillment' : 'Courier Envíame'}</strong> para <strong>${record.comercio}</strong> (${record.billing_periods?.name || ''}).
            </div>

            <div class="form-group" style="margin-bottom: 1.25rem;">
              <label class="form-label" style="font-weight: 600; display: block; margin-bottom: 0.35rem;">Número de Factura</label>
              <input type="number" id="reg-invoice-num" class="form-input" placeholder="Ej: 12345" min="1" required style="width: 100%; box-sizing: border-box; height: 38px; border-radius: var(--radius-sm);">
            </div>

            <div class="form-group" style="margin-bottom: 1.25rem;">
              <label class="form-label" style="font-weight: 600; display: block; margin-bottom: 0.35rem;">Archivo Factura PDF (Opcional)</label>
              <input type="file" id="reg-invoice-file" accept=".pdf" class="form-input" style="width: 100%; border: 1px solid var(--color-border); padding: 0.25rem 0.5rem; background: var(--color-surface); font-size: 0.8rem; height: 38px; border-radius: var(--radius-sm); box-sizing: border-box;">
              <p style="font-size: 0.7rem; color: var(--color-text-muted); margin: 0.25rem 0 0 0;">Si subes la factura, el cliente podrá verla y descargarla desde su portal.</p>
            </div>

            <!-- Selector de Envío de Aviso Automático -->
            <div class="form-group" style="margin-top: 1.5rem; margin-bottom: 0.5rem; display: flex; align-items: center; gap: 0.5rem; background: rgba(16, 185, 129, 0.05); padding: 0.75rem; border-radius: var(--radius-md); border: 1px solid rgba(16, 185, 129, 0.15);">
              <input type="checkbox" id="reg-invoice-notify" checked style="width: 18px; height: 18px; margin: 0; accent-color: var(--color-success); cursor: pointer;">
              <label for="reg-invoice-notify" style="font-size: 0.8rem; font-weight: 600; color: var(--color-text-main); cursor: pointer; user-select: none; margin: 0;">
                Enviar automáticamente aviso de factura emitida por correo (Brevo)
              </label>
            </div>
          </div>
          <div class="modal-footer" style="display: flex; justify-content: flex-end; gap: 0.5rem; border-top: 1px solid var(--color-border); padding-top: 1rem;">
            <button type="button" class="btn btn-outline" onclick="this.closest('.modal-overlay').remove()">Cancelar</button>
            <button type="submit" class="btn btn-primary" id="btn-submit-reg-invoice"><i class="ri-save-line"></i> Guardar y Confirmar</button>
          </div>
        </form>
      </div>
    `;
    document.body.appendChild(modal);

    // 3. Configurar el manejador del envío del formulario
    const form = document.getElementById('form-register-dashboard-invoice');
    form.addEventListener('submit', async (e) => {
      e.preventDefault();
      const btnSubmit = document.getElementById('btn-submit-reg-invoice');
      btnSubmit.disabled = true;
      btnSubmit.innerHTML = '<i class="ri-loader-4-line spin"></i> Registrando...';

      try {
        const num = parseInt(document.getElementById('reg-invoice-num').value.trim(), 10);
        if (isNaN(num) || num <= 0) {
          alert('Número de factura no válido.');
          btnSubmit.disabled = false;
          btnSubmit.innerHTML = '<i class="ri-save-line"></i> Guardar y Confirmar';
          return;
        }

        const fileInput = document.getElementById('reg-invoice-file');
        const notifyCheckbox = document.getElementById('reg-invoice-notify');

        const updates = {
          updated_at: new Date().toISOString()
        };

        // A. Subir PDF si se seleccionó uno
        if (fileInput && fileInput.files && fileInput.files[0]) {
          const file = fileInput.files[0];
          const sanitizedName = file.name.replace(/[^a-zA-Z0-9.-]/g, '_');
          const storagePath = `billing_files/${recordId}_factura_${serviceType}_${Date.now()}_${sanitizedName}`;

          const { error: uploadError } = await supabase.storage
            .from('payment_receipts')
            .upload(storagePath, file);

          if (uploadError) throw uploadError;

          const { data: urlData } = supabase.storage
            .from('payment_receipts')
            .getPublicUrl(storagePath);

          if (serviceType === 'fulfillment') {
            updates.factura_fulfillment_pdf_url = urlData.publicUrl;
          } else {
            updates.factura_enviame_pdf_url = urlData.publicUrl;
          }
        }

        // B. Actualizar número de factura y estado de facturación
        if (serviceType === 'fulfillment') {
          updates.factura_fulfillment = 'Emitida';
          updates.num_factura = num;
        } else {
          updates.factura_enviame = 'Emitida';
          updates.num_factura_enviame = num;
        }

        const { error: saveError } = await supabase
          .from('billing_records')
          .update(updates)
          .eq('id', recordId);

        if (saveError) throw saveError;

        // C. Enviar notificación automática por correo si corresponde
        if (notifyCheckbox && notifyCheckbox.checked) {
          try {
            const { data: { session } } = await supabase.auth.getSession();
            if (session) {
              const res = await fetch(`https://ejtjfaucnxbikrwjwwdu.supabase.co/functions/v1/send-billing-email`, {
                method: 'POST',
                headers: {
                  'Content-Type': 'application/json',
                  'Authorization': `Bearer ${session.access_token}`
                },
                body: JSON.stringify({
                  recordId,
                  serviceType,
                  emails: [],
                  customMessage: 'Factura oficial emitida.',
                  emailType: 'invoice_uploaded'
                })
              });

              if (res.ok) {
                // Actualizar la fecha de última notificación
                await supabase
                  .from('billing_records')
                  .update({ last_notified_at: new Date().toISOString() })
                  .eq('id', recordId);
              } else {
                const errJson = await res.json().catch(() => ({}));
                console.error('Error al enviar correo de notificación:', errJson.error || res.statusText);
              }
            }
          } catch (e) {
            console.warn('Fallo al disparar notificación de correo automática:', e);
          }
        }

        modal.remove();

        Swal.fire({
          icon: 'success',
          title: 'Factura registrada',
          text: 'La factura ha sido registrada exitosamente y se actualizó el panel.',
          confirmButtonText: 'Aceptar',
          confirmButtonColor: 'var(--color-primary)'
        });

        // D. Actualizar panel de Tareas Pendientes
        await refreshDashboardData();

        // E. Recargar tabla de facturación principal del periodo
        const periodId = record.period_id;
        const body = document.getElementById(`period-body-${periodId}`);
        if (body) {
          await loadBillingRecords(periodId, body);
        }

      } catch (err) {
        console.error('Error in markDashboardInvoiceAsIssued submit:', err);
        alert('Error al registrar factura: ' + err.message);
        btnSubmit.disabled = false;
        btnSubmit.innerHTML = '<i class="ri-save-line"></i> Guardar y Confirmar';
      }
    });

  } catch (err) {
    console.error('Error in markDashboardInvoiceAsIssued:', err);
    alert('Error al cargar datos del registro: ' + err.message);
    showSavingBadge(false);
  }
};

window.markDashboardFulfDetailSent = async function(recordId) {
  if (!confirm('¿Marcar el desglose de Fulfillment como enviado al cliente?')) return;
  
  showSavingBadge(true);
  try {
    const { error } = await supabase
      .from('billing_records')
      .update({ desglose_fulfillment: 'Enviado' })
      .eq('id', recordId);
      
    if (error) throw error;
    
    alert('Desglose marcado como Enviado.');
    await refreshDashboardData();
  } catch (err) {
    console.error(err);
    alert('Error: ' + err.message);
  } finally {
    showSavingBadge(false);
  }
};

window.markDashboardEnvDetailSent = async function(recordId) {
  if (!confirm('¿Marcar el detalle de Envíame como enviado y solicitar el pago? (Esto cambiará el estado del pago a "En espera")')) return;
  
  showSavingBadge(true);
  try {
    const { error } = await supabase
      .from('billing_records')
      .update({ pago_enviame: 'En espera' })
      .eq('id', recordId);
      
    if (error) throw error;
    
    alert('Detalle marcado como enviado y pago solicitado.');
    await refreshDashboardData();
  } catch (err) {
    console.error(err);
    alert('Error: ' + err.message);
  } finally {
    showSavingBadge(false);
  }
};

async function refreshDashboardData() {
  try {
    const { data: records, error } = await supabase
      .from('billing_records')
      .select('*, billing_periods(name, status, period_month, period_year)');
    if (error) throw error;
    cachedDashboardRecords = records || [];
    renderDashboardPendingView();
  } catch(err) {
    console.error('Error refreshing dashboard records:', err);
  }
}

async function renderInboxPage() {
  const appContent = document.getElementById('app-content');
  if (!appContent) return;
  
  appContent.innerHTML = `
    <div style="max-width: 900px; margin: 0 auto;">
      <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 1.5rem;">
        <h2 style="font-size: 1.5rem; color: var(--color-text-main); font-weight: 600;">Mi Inbox de Notificaciones</h2>
        <button id="inbox-mark-all-read-btn" class="btn btn-outline" style="border-color: var(--color-primary); color: var(--color-primary); display: none;">
          <i class="ri-check-double-line" style="margin-right: 0.25rem;"></i> Marcar todas leídas
        </button>
      </div>
      <div class="card">
        <div class="card-body" style="padding: 0;">
          <div id="inbox-list" style="min-height: 200px; position: relative;">
            <div style="padding: 3rem; text-align: center; color: var(--color-text-muted);">
              <i class="ri-loader-4-line spin" style="font-size: 2rem;"></i><br>Cargando...
            </div>
          </div>
        </div>
      </div>
    </div>
  `;

  await loadInboxData();
}

async function loadInboxData() {
  const list = document.getElementById('inbox-list');
  const markAllBtn = document.getElementById('inbox-mark-all-read-btn');
  if (!list) return;

  try {
    if (!currentMerchantId) return;
    
    // Fetch user's read records
    const { data: readRecords } = await supabase
      .from('user_notification_reads')
      .select('entity_id')
      .eq('user_id', currentMerchantId)
      .eq('entity_type', 'notification');
      
    const readIds = readRecords ? readRecords.map(r => r.entity_id) : [];

    const rolesToMatch = ['all', userRole];
    // Traer un historial más largo (100)
    const { data, error } = await supabase
      .from('dashboard_notifications')
      .select('*')
      .order('created_at', { ascending: false })
      .limit(100);
      
    if (error) throw error;

    const filteredData = data ? data.filter(n => {
      return (rolesToMatch.includes(n.target_role) && !n.user_id) || n.user_id === currentMerchantId;
    }) : [];

    if (!filteredData || filteredData.length === 0) {
      list.innerHTML = `
        <div style="padding: 4rem 2rem; text-align: center; color: var(--color-text-muted);">
          <div style="background: var(--color-surface-hover); width: 64px; height: 64px; border-radius: 50%; display: flex; align-items: center; justify-content: center; margin: 0 auto 1rem;">
            <i class="ri-inbox-archive-line" style="font-size: 2rem; color: var(--color-border);"></i>
          </div>
          <h3 style="font-size: 1.1rem; color: var(--color-text-main); margin-bottom: 0.25rem;">Bandeja vacía</h3>
          <p style="font-size: 0.9rem;">No tienes notificaciones en tu historial.</p>
        </div>`;
      if (markAllBtn) markAllBtn.style.display = 'none';
      return;
    }

    const unreadCount = filteredData.filter(n => !readIds.includes(n.id)).length;
    if (markAllBtn) {
      markAllBtn.style.display = unreadCount > 0 ? 'inline-flex' : 'none';
      
      // Remove old listener by replacing button
      const newBtn = markAllBtn.cloneNode(true);
      markAllBtn.parentNode.replaceChild(newBtn, markAllBtn);
      
      newBtn.addEventListener('click', async () => {
        try {
          const unreadItems = filteredData.filter(n => !readIds.includes(n.id));
          const inserts = unreadItems.map(item => ({
            user_id: currentMerchantId,
            entity_type: 'notification',
            entity_id: item.id
          }));
          
          if (inserts.length > 0) {
            newBtn.innerHTML = '<i class="ri-loader-4-line spin"></i> Marcando...';
            await supabase.from('user_notification_reads').insert(inserts);
            await loadInboxData();
          }
        } catch(err) {
          console.error(err);
        }
      });
    }

    list.innerHTML = filteredData.map(n => {
      const isReadLocally = readIds.includes(n.id);
      return `
      <div class="inbox-item ${isReadLocally ? 'read' : 'unread'}" style="padding: 1.25rem 1.5rem; border-bottom: 1px solid var(--color-border); display: flex; gap: 1rem; align-items: flex-start; transition: background-color 0.2s; background: ${isReadLocally ? 'transparent' : 'rgba(59, 130, 246, 0.05)'};">
        <div style="flex-shrink: 0; width: 40px; height: 40px; border-radius: 50%; background: ${isReadLocally ? 'var(--color-surface-hover)' : 'rgba(59, 130, 246, 0.15)'}; color: ${isReadLocally ? 'var(--color-text-muted)' : 'var(--color-primary)'}; display: flex; align-items: center; justify-content: center;">
          <i class="${isReadLocally ? 'ri-notification-badge-line' : 'ri-notification-3-fill'}" style="font-size: 1.25rem;"></i>
        </div>
        <div style="flex: 1;">
          <div style="display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 0.25rem;">
            <h4 style="margin: 0; font-size: 1rem; color: var(--color-text-main); font-weight: ${isReadLocally ? '500' : '600'};">${n.title}</h4>
            <span style="font-size: 0.75rem; color: var(--color-text-muted); white-space: nowrap; margin-left: 1rem;">${new Date(n.created_at).toLocaleString()}</span>
          </div>
          <p style="margin: 0; font-size: 0.9rem; color: ${isReadLocally ? 'var(--color-text-muted)' : 'var(--color-text-main)'}; line-height: 1.5;">${n.message}</p>
        </div>
        ${!isReadLocally ? `
          <button class="btn btn-outline mark-inbox-read-btn" data-id="${n.id}" title="Marcar como leída" style="padding: 0.25rem 0.5rem; font-size: 1.1rem; border: none; color: var(--color-primary); background: transparent;">
            <i class="ri-check-line"></i>
          </button>
        ` : `
          <div style="padding: 0.25rem 0.5rem; color: var(--color-text-muted); font-size: 1.1rem;"><i class="ri-check-double-line"></i></div>
        `}
      </div>
    `}).join('');

    document.querySelectorAll('.mark-inbox-read-btn').forEach(btn => {
      btn.addEventListener('click', async (e) => {
        e.stopPropagation();
        const id = btn.getAttribute('data-id');
        btn.innerHTML = '<i class="ri-loader-4-line spin"></i>';
        await supabase.from('user_notification_reads').insert([{ user_id: currentMerchantId, entity_type: 'notification', entity_id: id }]);
        await loadInboxData();
      });
    });

  } catch (err) {
    console.error('Error fetching inbox:', err);
    list.innerHTML = `<div style="padding: 2rem; color: var(--color-danger); text-align: center;">Error al cargar: ${err.message}</div>`;
  }
}

